import React, { useState, useEffect } from 'react';
import Button from 'react-bootstrap/Button';
import ButtonGroup from 'react-bootstrap/ButtonGroup';
import ButtonToolbar from 'react-bootstrap/ButtonToolbar';
import Col from 'react-bootstrap/Col';
import Container from 'react-bootstrap/Container';
import Row from 'react-bootstrap/Row';
import Table from 'react-bootstrap/Table';
import Chart from "react-apexcharts";

const range = (start, end) => Array.from(Array(end + 1).keys()).slice(start);

function App() {
  const menu = {
    period: [
      {
        period: 'month',
        label: 'year'
      },
      {
        period: 'day',
        label: 'month'
      },
      {
        period: 'hour',
        label: 'day'
      }
    ],
    target: {
      month: [
        '2021'
      ],
      day: {
        '2021': range(7, 11).map(d => String(d).padStart(2, '0'))
      },
      hour: {
        '2021': {
          '09': range(1, 30).map(d => String(d).padStart(2, '0')),
          '10': range(1, 31).map(d => String(d).padStart(2, '0')),
          '11': range(1, 30).map(d => String(d).padStart(2, '0'))
        }
      }
    }
  };
  const [datasource, setDatasource] = useState({
    unit: 'count',
    period: 'day',
    target: '2021-10'
  });
  const [data, setData] = useState([]);
  const [series, setSeries] = useState([]);
  useEffect(() => {
    fetch(`https://raw.githubusercontent.com/mozilla-platform-ops/bean-counter/main/data/${datasource.unit}-${datasource.period}-${datasource.target}.json`)
      .then((r) => r.json())
      .then((d) => {
        setData(d);
        setSeries([...new Set(d.map(x => x.queue))].sort().map(q => ({
          name: q,
          data: [...new Set(d.map(x => x.period))].sort().map(p => (d.find(x => x.period === p && x.queue ===q) || { tasks: 0 }).tasks)
        })))
      })
      .catch(console.error)
  }, [datasource]);
  return (
    <Container fluid>
      <Row>
        <Col>
          <h3>
            {datasource.target}
          </h3>
        </Col>
        <Col className="col-8">
          <ButtonToolbar aria-label="data selector" className="float-end">
            <ButtonGroup className="me-2" aria-label="period">
              {
                menu.period.map((p, pI) => (
                  <Button
                    key={pI}
                    variant={(datasource.period === p.period) ? 'primary' : 'secondary'}
                    onClick={() => setDatasource((ds) => ({
                      ...ds,
                      period: p.period,
                      target: (p.period === 'month')
                        ? `2021`
                        : (p.period === 'day')
                          ? `2021-10`
                          : `2021-10-01`
                    }))}
                    >
                    {p.label}
                  </Button>
                ))
              }
            </ButtonGroup>
            {
              (datasource.period === 'month')
                ? (
                    <ButtonGroup className="me-2" aria-label="target">
                      {
                        menu.target.month.map((y, yI) => (
                          <Button
                            key={yI}
                            variant={(datasource.target === y) ? 'primary' : 'secondary'}
                            >
                            {y}
                          </Button>
                        ))
                      }
                    </ButtonGroup>
                  )
                : (datasource.period === 'day')
                  ? (
                      <ButtonGroup className="me-2" aria-label="target">
                        {
                          menu.target.day[datasource.target.split('-')[0]].map((m, mI) => (
                            <Button
                              key={mI}
                              variant={(datasource.target.endsWith(`-${m}`)) ? 'primary' : 'secondary'}
                              onClick={() => setDatasource((ds) => ({
                                ...ds,
                                period: 'day',
                                target: `${ds.target.split('-')[0]}-${m}`
                              }))}
                              >
                              {m}
                            </Button>
                          ))
                        }
                      </ButtonGroup>
                    )
                  : (datasource.period === 'hour')
                    ? (
                        <>
                          <ButtonGroup className="me-2" aria-label="target">
                            {
                              menu.target.day['2021'].map((m, mI) => (
                                <Button
                                  key={mI}
                                  variant={(datasource.target.split('-')[1] === m) ? 'primary' : 'secondary'}
                                  onClick={() => setDatasource((ds) => ({
                                    ...ds,
                                    period: 'hour',
                                    target: `${ds.target.split('-')[0]}-${m}-${ds.target.split('-')[2]}`
                                  }))}
                                  >
                                  {m}
                                </Button>
                              ))
                            }
                          </ButtonGroup>
                          <ButtonGroup className="me-2" aria-label="target">
                            {
                              menu.target.hour[datasource.target.split('-')[0]][datasource.target.split('-')[1]].map((d, dI) => (
                                <Button
                                  key={dI}
                                  variant={(datasource.target.endsWith(`-${d}`)) ? 'primary' : 'secondary'}
                                  onClick={() => setDatasource((ds) => ({
                                    ...ds,
                                    period: 'hour',
                                    target: `${ds.target.split('-')[0]}-${ds.target.split('-')[1]}-${d}`
                                  }))}
                                  >
                                  {d}
                                </Button>
                              ))
                            }
                          </ButtonGroup>
                        </>
                      )
                    : null
            }
          </ButtonToolbar>
        </Col>
      </Row>
      <Row>
        <Chart
          options={{
            xaxis: { categories: [...new Set(data.map(x => x.period.split('-').pop()))].sort() }
          }}
          series={series}
          type="line"
          height="500"
        />
      </Row>
      <Row>
        <Col>
          <Table striped bordered hover>
            <thead>
              <tr>
                <th></th>
                {
                  [...new Set(data.map(x => x.period))].sort().map((period, pI) => (
                    <th key={pI} style={{ textAlign: 'right' }}>
                      {period.split('-').pop()}
                    </th>
                  ))
                }
              </tr>
            </thead>
            <tbody>
              {
                [...new Set(data.map(x => x.queue))].sort().map((queue, qI) => (
                  <tr key={qI}>
                    <th>{queue}</th>
                    {
                      [...new Set(data.map(x => x.period))].sort().map((period, pI) => (
                        <td
                          key={`${qI}-${pI}`}
                          style={{ textAlign: 'right' }}
                          className={
                            !data.find((x) => x.queue === queue && x.period === period)
                              ? 'text-muted'
                              : 'text-dark'
                            }
                          >
                          {(data.find((x) => x.queue === queue && x.period === period) || { tasks: 0 }).tasks}
                        </td>
                      ))
                    }
                  </tr>
                ))
              }
            </tbody>
          </Table>
        </Col>
      </Row>
    </Container>
  );
}

export default App;
